  "inlineSchema": "// ContentFlow data model.\n// Content is the central entity: Ideas Bank, Posts, and Calendar are all\n// views over this same table, filtered by `status` / `scheduledAt`.\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../lib/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Plan {\n  starter\n  pro\n  studio\n}\n\nenum MemberRole {\n  owner\n  editor\n  viewer\n}\n\nenum ContentType {\n  post\n  story\n  reel\n  video\n  carousel\n}\n\nenum ContentStatus {\n  idea\n  draft\n  scheduled\n  published\n  archived\n}\n\nenum SocialPlatform {\n  instagram\n  tiktok\n  x\n  youtube\n  linkedin\n}\n\nenum SocialAccountStatus {\n  connected\n  disconnected\n  expired\n}\n\nenum TaskStatus {\n  todo\n  in_progress\n  done\n}\n\nenum MessageStatus {\n  unread\n  read\n  replied\n}\n\nenum AssistantType {\n  trends\n  comment_reply\n  engagement\n  growth\n  captions\n  viral_ideas\n}\n\n/// Mirrors a Supabase Auth user (auth.users). `id` is the same UUID Supabase\n/// issues on sign-up — this table is a public-schema profile row, not the\n/// auth system itself.\nmodel User {\n  id          String            @id @db.Uuid\n  email       String            @unique\n  name        String?\n  createdAt   DateTime          @default(now())\n  memberships WorkspaceMember[]\n  tasks       Task[]\n  content     Content[]\n\n  @@map(\"users\")\n}\n\nmodel Workspace {\n  id        String            @id @default(uuid())\n  name      String\n  plan      Plan              @default(starter)\n  createdAt DateTime          @default(now())\n  members   WorkspaceMember[]\n  brands    Brand[]\n  content   Content[]\n  media     Media[]\n  messages  Message[]\n\n  @@map(\"workspaces\")\n}\n\nmodel WorkspaceMember {\n  id          String     @id @default(uuid())\n  userId      String     @db.Uuid\n  workspaceId String\n  role        MemberRole @default(owner)\n  createdAt   DateTime   @default(now())\n\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, workspaceId])\n  @@map(\"workspace_members\")\n}\n\nmodel Brand {\n  id          String   @id @default(uuid())\n  workspaceId String\n  name        String\n  createdAt   DateTime @default(now())\n\n  workspace      Workspace       @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  brandVoice     BrandVoice?\n  content        Content[]\n  media          Media[]\n  messages       Message[]\n  socialAccounts SocialAccount[]\n\n  @@map(\"brands\")\n}\n\nmodel BrandVoice {\n  id           String   @id @default(uuid())\n  brandId      String   @unique\n  tone         String?\n  wordsToAvoid String[]\n  examplePosts String[]\n\n  brand Brand @relation(fields: [brandId], references: [id], onDelete: Cascade)\n\n  @@map(\"brand_voices\")\n}\n\n/// The central entity. Ideas Bank = status \"idea\"; Posts = status draft /\n/// scheduled / published; Calendar = rows with scheduledAt set. Same table,\n/// same id, same history — moving between views just changes `status`.\nmodel Content {\n  id          String           @id @default(uuid())\n  workspaceId String\n  brandId     String\n  campaignId  String?\n  title       String\n  body        String?          @db.Text\n  type        ContentType\n  status      ContentStatus    @default(idea)\n  platforms   SocialPlatform[]\n  scheduledAt DateTime?\n  publishedAt DateTime?\n  createdBy   String           @db.Uuid\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  brand     Brand     @relation(fields: [brandId], references: [id], onDelete: Cascade)\n  author    User      @relation(fields: [createdBy], references: [id])\n  tasks     Task[]\n  media     Media[]\n  metrics   Metric[]\n  messages  Message[]\n\n  @@index([workspaceId, status])\n  @@index([brandId, status])\n  @@index([scheduledAt])\n  @@map(\"content\")\n}\n\nmodel Task {\n  id         String     @id @default(uuid())\n  contentId  String\n  title      String\n  dueDate    DateTime?\n  status     TaskStatus @default(todo)\n  assigneeId String?    @db.Uuid\n  createdAt  DateTime   @default(now())\n\n  content  Content @relation(fields: [contentId], references: [id], onDelete: Cascade)\n  assignee User?   @relation(fields: [assigneeId], references: [id])\n\n  @@map(\"tasks\")\n}\n\nmodel Media {\n  id          String   @id @default(uuid())\n  workspaceId String\n  brandId     String\n  contentId   String?\n  fileUrl     String\n  type        String\n  uploadedAt  DateTime @default(now())\n\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  brand     Brand     @relation(fields: [brandId], references: [id], onDelete: Cascade)\n  content   Content?  @relation(fields: [contentId], references: [id], onDelete: SetNull)\n\n  @@map(\"media\")\n}\n\n/// Snapshots over time, not just the latest value — one row per capture.\nmodel Metric {\n  id         String         @id @default(uuid())\n  contentId  String\n  platform   SocialPlatform\n  likes      Int            @default(0)\n  comments   Int            @default(0)\n  shares     Int            @default(0)\n  reach      Int            @default(0)\n  capturedAt DateTime       @default(now())\n\n  content Content @relation(fields: [contentId], references: [id], onDelete: Cascade)\n\n  @@index([contentId, capturedAt])\n  @@map(\"metrics\")\n}\n\nmodel SocialAccount {\n  id                String              @id @default(uuid())\n  brandId           String\n  platform          SocialPlatform\n  oauthAccessToken  String?\n  oauthRefreshToken String?\n  status            SocialAccountStatus @default(disconnected)\n  connectedAt       DateTime?\n\n  brand Brand @relation(fields: [brandId], references: [id], onDelete: Cascade)\n\n  @@unique([brandId, platform])\n  @@map(\"social_accounts\")\n}\n\n/// contentId is optional (a DM isn't always about one post), but every\n/// message still comes in through a specific brand's connected account, so\n/// workspaceId/brandId are required for tenant scoping.\nmodel Message {\n  id          String         @id @default(uuid())\n  workspaceId String\n  brandId     String\n  contentId   String?\n  platform    SocialPlatform\n  sender      String\n  body        String         @db.Text\n  receivedAt  DateTime       @default(now())\n  status      MessageStatus  @default(unread)\n\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  brand     Brand     @relation(fields: [brandId], references: [id], onDelete: Cascade)\n  content   Content?  @relation(fields: [contentId], references: [id], onDelete: SetNull)\n\n  @@index([workspaceId, status])\n  @@map(\"messages\")\n}\n\nmodel AssistantLog {\n  id            String        @id @default(uuid())\n  assistantType AssistantType\n  input         String        @db.Text\n  output        String        @db.Text\n  createdAt     DateTime      @default(now())\n\n  @@map(\"assistant_logs\")\n}\n",
